// ==================== Data Models ====================

data class WalletBalance(
    val amount: BigDecimal,
    val currency: String = "USD",
    val lastUpdated: Long = System.currentTimeMillis()
)

data class WalletTransaction(
    val id: String = UUID.randomUUID().toString(),
    val type: TransactionType,
    val amount: BigDecimal,
    val currency: String = "USD",
    val description: String,
    val status: TransactionStatus = TransactionStatus.PENDING,
    val timestamp: Long = System.currentTimeMillis(),
    val metadata: Map<String, String> = emptyMap()
)

enum class TransactionType {
    CREDIT, DEBIT, PURCHASE, REFUND, TOP_UP
}

enum class TransactionStatus {
    PENDING, PROCESSING, COMPLETED, FAILED, CANCELLED, REFUNDED
}

data class PaymentResult(
    val success: Boolean,
    val transactionId: String? = null,
    val message: String = "",
    val errorCode: Int? = null
)

data class ProductInfo(
    val productId: String,
    val title: String,
    val description: String,
    val price: String,
    val priceAmountMicros: Long,
    val priceCurrencyCode: String,
    val type: ProductType
)

enum class ProductType {
    IN_APP, SUBSCRIPTION
}

sealed class PaymentState {
    object Idle : PaymentState()
    object Loading : PaymentState()
    data class Success(val result: PaymentResult) : PaymentState()
    data class Error(val message: String, val code: Int? = null) : PaymentState()
    data class ProductsLoaded(val products: List<ProductInfo>) : PaymentState()
    data class WalletUpdated(val balance: WalletBalance) : PaymentState()
    data class TransactionHistoryLoaded(val transactions: List<WalletTransaction>) : PaymentState()
}

// ==================== Security Module ====================

class SecurityManager(private val context: Context) {

    companion object {
        private const val KEYSTORE_ALIAS = "PaymentKeyAlias"
        private const val ANDROID_KEYSTORE = "AndroidKeyStore"
        private const val AES_GCM_NOPADDING = "AES/GCM/NoPadding"
        private const val GCM_TAG_LENGTH = 128
        private const val GCM_IV_LENGTH = 12
        private const val ENCRYPTED_PREFS_FILE = "encrypted_payment_prefs"
        private const val TAG = "SecurityManager"
    }

    private val keyStore: KeyStore by lazy {
        KeyStore.getInstance(ANDROID_KEYSTORE).apply { load(null) }
    }

    private val masterKey: MasterKey by lazy {
        MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()
    }

    val encryptedPrefs by lazy {
        EncryptedSharedPreferences.create(
            context,
            ENCRYPTED_PREFS_FILE,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    init {
        generateKeyIfNeeded()
    }

    private fun generateKeyIfNeeded() {
        try {
            if (!keyStore.containsAlias(KEYSTORE_ALIAS)) {
                val keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES,
                    ANDROID_KEYSTORE
                )
                val builder = KeyGenParameterSpec.Builder(
                    KEYSTORE_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
                )
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setKeySize(256)
                    .setRandomizedEncryptionRequired(true)

                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                    builder.setInvalidatedByBiometricEnrollment(false)
                }
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                    builder.setUnlockedDeviceRequired(false)
                    builder.setIsStrongBoxBacked(isStrongBoxAvailable())
                }

                keyGenerator.init(builder.build())
                keyGenerator.generateKey()
            }
        } catch (e: Exception) {
            Log.e(TAG, "Key generation failed", e)
        }
    }

    private fun isStrongBoxAvailable(): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            context.packageManager.hasSystemFeature("android.hardware.strongbox_keystore")
        } else {
            false
        }
    }

    private fun getSecretKey(): SecretKey {
        val entry = keyStore.getEntry(KEYSTORE_ALIAS, null) as KeyStore.SecretKeyEntry
        return entry.secretKey
    }

    fun encrypt(plainText: String): String {
        return try {
            val cipher = Cipher.getInstance(AES_GCM_NOPADDING)
            cipher.init(Cipher.ENCRYPT_MODE, getSecretKey())
            val iv = cipher.iv
            val encryptedBytes = cipher.doFinal(plainText.toByteArray(Charsets.UTF_8))
            val combined = ByteArray(iv.size + encryptedBytes.size)
            System.arraycopy(iv, 0, combined, 0, iv.size)
            System.arraycopy(encryptedBytes, 0, combined, iv.size, encryptedBytes.size)
            Base64.encodeToString(combined, Base64.NO_WRAP)
        } catch (e: Exception) {
            Log.e(TAG, "Encryption failed", e)
            throw SecurityException("Failed to encrypt data", e)
        }
    }

    fun decrypt(encryptedText: String): String {
        return try {
            val combined = Base64.decode(encryptedText, Base64.NO_WRAP)
            val iv = combined.copyOfRange(0, GCM_IV_LENGTH)
            val encryptedBytes = combined.copyOfRange(GCM_IV_LENGTH, combined.size)
            val cipher = Cipher.getInstance(AES_GCM_NOPADDING)
            val spec = GCMParameterSpec(GCM_TAG_LENGTH, iv)
            cipher.init(Cipher.DECRYPT_MODE, getSecretKey(), spec)
            String(cipher.doFinal(encryptedBytes), Charsets.UTF_8)
        } catch (e: Exception) {
            Log.e(TAG, "Decryption failed", e)
            throw SecurityException("Failed to decrypt data", e)
        }
    }

    fun hashData(data: String): String {
        val salt = generateSalt()
        val saltedData = salt + data
        val digest = MessageDigest.getInstance("SHA-256")
        val hashBytes = digest.digest(saltedData.toByteArray(Charsets.UTF_8))
        return Base64.encodeToString(salt.toByteArray() + hashBytes, Base64.NO_WRAP)
    }

    private fun generateSalt(): String {
        val salt = ByteArray(16)
        SecureRandom().nextBytes(salt)
        return Base64.encodeToString(salt, Base64.NO_WRAP)
    }

    fun generateTransactionToken(): String {
        val random = SecureRandom()
        val bytes = ByteArray(32)
        random.nextBytes(bytes)
        return Base64.encodeToString(bytes, Base64.URL_SAFE or Base64.NO_WRAP)
    }

    fun sanitizeInput(input: String): String {
        return input.replace(Regex("[<>\"'&;]"), "")
            .trim()
            .take(500)
    }

    fun clearSensitiveData() {
        encryptedPrefs.edit().clear().apply()
    }
}

// ==================== Wallet Manager ====================

class WalletManager(private val context: Context) {

    private val securityManager = SecurityManager(context)
    private val gson = Gson()

    companion object {
        private const val KEY_WALLET_BALANCE = "wallet_balance"
        private const val KEY_TRANSACTIONS = "wallet_transactions"
        private const val KEY_WALLET_ID = "wallet_id"
        private const val MAX_TRANSACTION_HISTORY = 500
        private const val TAG = "WalletManager"
    }

    private val _balanceFlow = MutableStateFlow(getBalance())
    val balanceFlow: StateFlow<WalletBalance> = _balanceFlow.asStateFlow()

    private val transactionLock = Any()

    fun getWalletId(): String {
        val prefs = securityManager.encryptedPrefs
        var walletId = prefs.getString(KEY_WALLET_ID, null)
        if (walletId == null) {
            walletId = UUID.randomUUID().toString()
            prefs.edit().putString(KEY_WALLET_ID, walletId).apply()
        }
        return walletId
    }

    fun getBalance(): WalletBalance {
        return try {
            val encrypted = securityManager.encryptedPrefs.getString(KEY_WALLET_BALANCE, null)
            if (encrypted != null) {
                val json = securityManager.decrypt(encrypted)
                gson.fromJson(json, WalletBalance::class.java)
            } else {
                WalletBalance(BigDecimal.ZERO)
            }
        } catch (e: Exception) {
            Log.e(TAG, "Failed to get balance", e)
            WalletBalance(BigDecimal.ZERO)
        }
    }

    private fun saveBalance(balance: WalletBalance) {
        try {
            val json = gson.toJson(balance)
            val encrypted = securityManager.encrypt(json)
            securityManager.encryptedPrefs.edit()
                .putString(KEY_WALLET_BALANCE, encrypted)
                .apply()
            _balanceFlow.value = balance
        } catch (e: Exception) {
            Log.e(TAG, "Failed to save balance", e)
            throw e
        }
    }

    fun getTransactionHistory(): List<WalletTransaction> {
        return try {
            val encrypted = securityManager.encryptedPrefs.getString(KEY_TRANSACTIONS, null)
            if (encrypted != null) {
                val json = securityManager.decrypt(encrypted)
                val type = object : TypeToken<List<WalletTransaction>>() {}.type
                gson.fromJson(json, type)
            } else {
                emptyList()
            }
        } catch (e: Exception) {
            Log.e(TAG, "Failed to get transaction history", e)
            emptyList()
        }
    }

    private fun saveTransactions(transactions: List<WalletTransaction>) {
        try {
            val trimmed = if (transactions.size > MAX_TRANSACTION_HISTORY) {
                transactions.sortedByDescending { it.timestamp }.take(MAX_TRANSACTION_HISTORY)
            } else {
                transactions
            }
            val json = gson.toJson(trimmed)
            val encrypted = securityManager.encrypt(json)
            securityManager.encryptedPrefs.edit()
                .putString(KEY_TRANSACTIONS, encrypted)
                .apply()
        } catch (e: Exception) {
            Log.e(TAG, "Failed to save transactions", e)
        }
    }

    fun topUp(amount: BigDecimal, description: String = "Wallet Top Up"): PaymentResult {
        synchronized(transactionLock) {
            return try {
                if (amount <= BigDecimal.ZERO) {
                    return PaymentResult(false, message = "Amount must be positive", errorCode = 1001)
                }

                val currentBalance = getBalance()
                val newBalance = currentBalance.copy(
                    amount = currentBalance.amount + amount,
                    lastUpdated = System.currentTimeMillis()
                )

                val transaction = WalletTransaction(
                    type = TransactionType.TOP_UP,
                    amount = amount,
                    description = securityManager.sanitizeInput(description),
                    status = TransactionStatus.COMPLETED
                )

                saveBalance(newBalance)
                val transactions = getTransactionHistory().toMutableList()
                transactions.add(0, transaction)
                saveTransactions(transactions)

                PaymentResult(
                    success = true,
                    transactionId = transaction.id,
                    message = "Top up successful"
                )
            } catch (e: Exception) {
                Log.e(TAG, "Top up failed", e)
                PaymentResult(false, message = "Top up failed: ${e.message}", errorCode = 1002)
            }
        }
    }

    fun debit(amount: BigDecimal, description: String = "Purchase"): PaymentResult {
        synchronized(transactionLock) {
            return try {
                if (amount <= BigDecimal.ZERO) {
                    return PaymentResult(false, message = "Amount must be positive", errorCode = 1001)
                }

                val currentBalance = getBalance()
                if (currentBalance.amount < amount) {
                    return PaymentResult(false, message = "Insufficient balance", errorCode = 1003)
                }

                val newBalance = currentBalance.copy(
                    amount = currentBalance.amount - amount,
                    lastUpdated = System.currentTimeMillis()
                )

                val transaction = WalletTransaction(
                    type = TransactionType.DEBIT,
                    amount = amount,
                    description = securityManager.sanitizeInput(description),
                    status = TransactionStatus.COMPLETED
                )

                saveBalance(newBalance)
                val transactions = getTransactionHistory().toMutableList()
                transactions.add(0, transaction)
                saveTransactions(transactions)

                PaymentResult(
                    success = true,
                    transactionId = transaction.id,
                    message = "Debit successful"
                )
            } catch (e: Exception) {
                Log.e(TAG, "Debit failed", e)
                PaymentResult(false, message = "Debit failed: ${e.message}", errorCode = 1004)
            }
        }
    }

    fun credit(amount: BigDecimal, description: String = "Credit"): PaymentResult {
        synchronized(transactionLock) {
            return try {
                if (amount <= BigDecimal.ZERO) {
                    return PaymentResult(false, message = "Amount must be positive", errorCode = 1001)
                }

                val currentBalance = getBalance()
                val newBalance = currentBalance.copy(
                    amount = currentBalance.amount + amount,
                    lastUpdated = System.currentTimeMillis()
                )

                val transaction = WalletTransaction(
                    type = TransactionType.CREDIT,
                    amount = amount,
                    description = securityManager.sanitizeInput(description),
                    status = TransactionStatus.COMPLETED
                )

                saveBalance(newBalance)
                val transactions = getTransactionHistory().toMutableList()
                transactions.add(0, transaction)
                saveTransactions(transactions)

                PaymentResult(
                    success = true,
                    transactionId = transaction.id,
                    message = "Credit successful"
                )
            } catch (e: Exception) {
                Log.e(TAG, "Credit failed", e)
                PaymentResult(false, message = "Credit failed: ${e.message}", errorCode = 1005)
            }
        }
    }

    fun refund(originalTransactionId: String, amount: BigDecimal): PaymentResult {
        synchronized(transactionLock) {
            return try {
                val transactions = getTransactionHistory()
                val originalTransaction = transactions.find { it.id == originalTransactionId }
                    ?: return PaymentResult(false, message = "Original transaction not found", errorCode = 1006)

                if (originalTransaction.status == TransactionStatus.REFUNDED) {
                    return PaymentResult(false, message = "Transaction already refunded", errorCode = 1007)
                }

                if (amount > originalTransaction.amount) {
                    return PaymentResult(false, message = "Refund amount exceeds original", errorCode = 1008)
                }

                val currentBalance = getBalance()
                val newBalance = currentBalance.copy(
                    amount = currentBalance.amount + amount,
                    lastUpdated = System.currentTimeMillis()
                )

                val refundTransaction = WalletTransaction(
                    type = TransactionType.REFUND,
                    amount = amount,
                    description = "Refund for transaction $originalTransactionId",
                    status = TransactionStatus.COMPLETED,
                    metadata = mapOf("originalTransactionId" to originalTransactionId)
                )

                saveBalance(newBalance)
                val updatedTransactions = transactions.map {
                    if (it.id == originalTransactionId) it.copy(status = TransactionStatus.REFUNDED)
                    else it
                }.toMutableList()
                updatedTransactions.add(0, refundTransaction)
                saveTransactions(updatedTransactions)

                PaymentResult(
                    success = true,
                    transactionId = refundTransaction.id,
                    message = "Refund successful"
                )
            } catch (e: Exception) {
                Log.e(TAG, "Refund failed", e)
                PaymentResult(false, message = "Refund failed: ${e.message}", errorCode = 1009)
            }
        }
    }
}

// ==================== Google Play Billing Manager ====================

class BillingManager(
    private val context: Context,
    private val coroutineScope: CoroutineScope
) : PurchasesUpdatedListener {

    companion object {
        private const val TAG = "BillingManager"
        private const val MAX_RETRY_ATTEMPTS = 3
        private const val RETRY_DELAY_MS = 2000L
    }

    private var billingClient: BillingClient? = null
    private val _purchaseState = MutableSharedFlow<PaymentState>(replay = 1)
    val purchaseState: SharedFlow<PaymentState> = _purchaseState.asSharedFlow()

    private val productDetailsMap = ConcurrentHashMap<String, ProductDetails>()
    private val pendingPurchases = ConcurrentHashMap<String, Purchase>()
    private val securityManager = SecurityManager(context)

    private var retryCount = 0
    private var isConnecting = false

    fun initialize() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()
        connectToPlayBilling()
    }

    private fun connectToPlayBilling() {
        if (isConnecting) return
        isConnecting = true

        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                isConnecting = false
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.d(TAG, "Billing client connected")
                    retryCount = 0
                    coroutineScope.launch {
                        queryExistingPurchases()
                    }
                } else {
                    Log.e(TAG, "Billing setup failed: ${billingResult.debugMessage}")
                    retryConnection()
                }
            }

            override fun onBillingServiceDisconnected() {
                isConnecting = false
                Log.w(TAG, "Billing service disconnected")
                retryConnection()
            }
        })
    }

    private fun retryConnection() {
        if (retryCount < MAX_RETRY_ATTEMPTS) {
            retryCount++
            coroutineScope.launch {
                delay(RETRY_DELAY_MS * retryCount)
                connectToPlayBilling()
            }
        } else {
            coroutineScope.launch {
                _purchaseState.emit(
                    PaymentState.Error("Failed to connect to billing service after $MAX_RETRY_ATTEMPTS attempts")
                )
            }
        }
    }

    private fun ensureConnected(): Boolean {
        return billingClient?.isReady == true
    }

    suspend fun queryProducts(
        productIds: List<String>,
        productType: String = BillingClient.ProductType.INAPP
    ): List<ProductInfo> {
        if (!ensureConnected()) {
            _purchaseState.emit(PaymentState.Error("Billing client not connected"))
            return emptyList()
        }

        val productList = productIds.map { productId ->
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(productType)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        return withContext(Dispatchers.IO) {
            try {
                val result = billingClient!!.queryProductDetails(params)
                if (result.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    val products = result.productDetailsList?.map { details ->
                        productDetailsMap[details.productId] = details
                        val oneTimePurchaseOfferDetails = details.oneTimePurchaseOfferDetails
                        ProductInfo(
                            productId = details.productId,
                            title = details.title,
                            description = details.description,
                            price = oneTimePurchaseOfferDetails?.formattedPrice ?: "",
                            priceAmountMicros = oneTimePurchaseOfferDetails?.priceAmountMicros ?: 0L,
                            priceCurrencyCode = oneTimePurchaseOfferDetails?.priceCurrencyCode ?: "",
                            type = if (productType == BillingClient.ProductType.INAPP) ProductType.IN_APP else ProductType.SUBSCRIPTION
                        )
                    } ?: emptyList()

                    _purchaseState.emit(PaymentState.ProductsLoaded(products))
                    products
                } else {
                    _purchaseState.emit(PaymentState.Error("Query failed: ${result.billingResult.debugMessage}"))
                    emptyList()
                }
            } catch (e: Exception) {
                Log.e(TAG, "Query products failed", e)
                _purchaseState.emit(PaymentState.Error("Query products failed: ${e.message}"))
                emptyList()
            }
        }
    }

    fun launchPurchaseFlow(activity: Activity, productId: String): Boolean {
        if (!ensureConnected()) {
            coroutineScope.launch {
                _purchaseState.emit(PaymentState.Error("Billing client not connected"))
            }
            return false
        }

        val productDetails = productDetailsMap[productId]
        if (productDetails == null) {
            coroutineScope.launch {
                _purchaseState.emit(PaymentState.Error("Product not found. Query products first."))
            }
            return false
        }

        val productDetailsParamsList = listOf(
            BillingFlowParams.ProductDetailsParams.newBuilder()
                .setProductDetails(productDetails)
                .build()
        )

        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(productDetailsParamsList)
            .build()

        coroutineScope.launch {
            _purchaseState.emit(PaymentState.Loading)
        }

        val billingResult = billingClient!!.launchBillingFlow(activity, billingFlowParams)
        return billingResult.responseCode == BillingClient.BillingResponseCode.OK
    }

    fun launchSubscriptionFlow(
        activity: Activity,
        productId: String,
        offerToken: String
    ): Boolean {
        if (!ensureConnected()) {
            coroutineScope.launch {
                _purchaseState.emit(PaymentState.Error("Billing client not connected"))
            }
            return false
        }

        val productDetails = productDetailsMap[productId]
        if (productDetails == null) {
            coroutineScope.launch {
                _purchaseState.emit(PaymentState.Error("Product not found"))
            }
            return false
        }

        val productDetailsParamsList = listOf(
            BillingFlowParams.ProductDetailsParams.newBuilder()
                .setProductDetails(productDetails)
                .setOfferToken(offerToken)
                .build()
        )

        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(productDetailsParamsList)
            .build()

        coroutineScope.launch {
            _purchaseState.emit(PaymentState.Loading)
        }

        val billingResult = billingClient!!.launchBillingFlow(activity, billingFlowParams)
        return billingResult.responseCode == BillingClient.BillingResponseCode.OK
    }

    override fun onPurchasesUpdated(
        billingResult: BillingResult,
        purchases: MutableList<Purchase>?
    ) {
        coroutineScope.launch {
            when (billingResult.responseCode) {
                BillingClient.BillingResponseCode.OK -> {
                    purchases?.forEach { purchase ->
                        handlePurchase(purchase)
                    }
                }
                BillingClient.BillingResponseCode.USER_CANCELED -> {
                    _purchaseState.emit(PaymentState.Error("Purchase cancelled by user", billingResult.responseCode))
                }
                BillingClient.BillingResponseCode.ITEM_ALREADY_OWNED -> {
                    _purchaseState.emit(PaymentState.Error("Item already owned", billingResult.responseCode))
                    queryExistingPurchases()
                }
                else -> {
                    _purchaseState.emit(
                        PaymentState.Error(
                            "Purchase failed: ${billingResult.debugMessage}",
                            billingResult.responseCode
                        )
                    )
                }
            }
        }
    }

    private suspend fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            if (!verifyPurchase(purchase)) {
                _purchaseState.emit(PaymentState.Error("Purchase verification failed"))
                return
            }

            if (!purchase.isAcknowledged) {
                acknowledgePurchase(purchase)
            }

            // For consumable products
            pendingPurchases[purchase.orderId ?: purchase.purchaseToken] = purchase

            _purchaseState.emit(
                PaymentState.Success(
                    PaymentResult(
                        success = true,
                        transactionId = purchase.orderId,
                        message = "Purchase successful"
                    )
                )
            )
        } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
            _purchaseState.emit(
                PaymentState.Success(
                    PaymentResult(
                        success = true,
                        transactionId = purchase.orderId,
                        message = "Purchase pending"
                    )
                )
            )
        }
    }

    private fun verifyPurchase(purchase: Purchase): Boolean {
        // In production, verify the purchase signature on your backend server
        // This is a local verification placeholder
        return try {
            purchase.purchaseToken.isNotEmpty() &&
                    purchase.products.isNotEmpty()
            // TODO: Add server-side verification
            // verifyPurchaseOnServer(purchase.originalJson, purchase.signature)
        } catch (e: Exception) {
            Log.e(TAG, "Purchase verification error", e)
            false
        }
    }

    private suspend fun acknowledgePurchase(purchase: Purchase) {
        val acknowledgeParams = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        withContext(Dispatchers.IO) {
            val result = billingClient!!.acknowledgePurchase(acknowledgeParams)
            if (result.responseCode != BillingClient.BillingResponseCode.OK) {
                Log.e(TAG, "Acknowledge failed: ${result.debugMessage}")
            }
        }
    }

    suspend fun consumePurchase(purchaseToken: String): Boolean {
        if (!ensureConnected()) return false

        val consumeParams = ConsumeParams.newBuilder()
            .setPurchaseToken(purchaseToken)
            .build()

        return withContext(Dispatchers.IO) {
            val result = billingClient!!.consumePurchase(consumeParams)
            result.billingResult.responseCode == BillingClient.BillingResponseCode.OK
        }
    }

    private suspend fun queryExistingPurchases() {
        if (!ensureConnected()) return

        withContext(Dispatchers.IO) {
            // Query in-app purchases
            val inAppParams = QueryPurchasesParams.newBuilder()
                .setProductType(BillingClient.ProductType.INAPP)
                .build()
            val inAppResult = billingClient!!.queryPurchasesAsync(inAppParams)

            if (inAppResult.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                inAppResult.purchasesList.forEach { purchase ->
                    if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
                        handlePurchase(purchase)
                    }
                }
            }

            // Query subscriptions
            val subsParams = QueryPurchasesParams.newBuilder()
                .setProductType(BillingClient.ProductType.SUBS)
                .build()
            val subsResult = billingClient!!.queryPurchasesAsync(subsParams)

            if (subsResult.billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                subsResult.purchasesList.forEach { purchase ->
                    if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
                        handlePurchase(purchase)
                    }
                }
            }
        }
    }

    fun destroy() {
        billingClient?.endConnection()
        billingClient = null
        productDetailsMap.clear()
        pendingPurchases.clear()
    }
}

// ==================== Rate Limiter ====================

class RateLimiter(
    private val maxRequests: Int = 10,
    private val windowMs: Long = 60_000L
) {
    private val requestTimestamps = mutableListOf<Long>()

    @Synchronized
    fun allowRequest(): Boolean {
        val now = System.currentTimeMillis()
        requestTimestamps.removeAll { now - it > windowMs }
        return if (requestTimestamps.size < maxRequests) {
            requestTimestamps.add(now)
            true
        } else {
            false
        }
    }
}

// ==================== Transaction Validator ====================

object TransactionValidator {

    private const val MAX_AMOUNT = 10_000.0
    private const val MIN_AMOUNT = 0.01

    fun validateAmount(amount: BigDecimal): ValidationResult {
        return when {
            amount <= BigDecimal.ZERO -> ValidationResult(false, "Amount must be positive")
            amount < BigDecimal(MIN_AMOUNT) -> ValidationResult(false, "Amount below minimum ($MIN_AMOUNT)")
            amount > BigDecimal(MAX_AMOUNT) -> ValidationResult(false, "Amount exceeds maximum ($MAX_AMOUNT)")
            amount.scale() > 2 -> ValidationResult(false, "Amount cannot have more than 2 decimal places")
            else -> ValidationResult(true)
        }
    }

    fun validateCurrency(currency: String): ValidationResult {
        val validCurrencies = setOf("USD", "EUR", "GBP", "JPY", "CAD", "AUD", "INR")
        return if (currency.uppercase() in validCurrencies) {
            ValidationResult(true)
        } else {
            ValidationResult(false, "Unsupported currency: $currency")
        }
    }

    data class ValidationResult(
        val isValid: Boolean,
        val message: String = ""
    )
}

// ==================== Payment ViewModel ====================

class PaymentViewModel(
    private val context: Context
) : ViewModel() {

    private val billingManager = BillingManager(context, viewModelScope)
    private val walletManager = WalletManager(context)
    private val rateLimiter = RateLimiter()

    private val _paymentState = MutableLiveData<PaymentState>(PaymentState.Idle)
    val paymentState: LiveData<PaymentState> = _paymentState

    val walletBalance: StateFlow<WalletBalance> = walletManager.balanceFlow

    val billingState: SharedFlow<PaymentState> = billingManager.purchaseState

    init {
        billingManager.initialize()
        observeBillingUpdates()
    }

    private fun observeBillingUpdates() {
        viewModelScope.launch {
            billingManager.purchaseState.collect { state ->
                _paymentState.postValue(state)
            }
        }
    }

    fun queryProducts(productIds: List<String>, productType: String = "inapp") {
        viewModelScope.launch {
            _paymentState.value = PaymentState.Loading
            billingManager.queryProducts(productIds, productType)
        }
    }

    fun purchaseProduct(activity: Activity, productId: String) {
        if (!rateLimiter.allowRequest()) {
            _paymentState.value = PaymentState.Error("Too many requests. Please try again later.")
            return
        }
        billingManager.launchPurchaseFlow(activity, productId)
    }

    fun purchaseSubscription(activity: Activity, productId: String, offerToken: String) {
        if (!rateLimiter.allowRequest()) {
            _paymentState.value = PaymentState.Error("Too many requests. Please try again later.")
            return
        }
        billingManager.launchSubscriptionFlow(activity, productId, offerToken)
    }

    fun consumePurchase(purchaseToken: String) {
        viewModelScope.launch {
            val success = billingManager.consumePurchase(purchaseToken)
            if (success) {
                _paymentState.value = PaymentState.Success(
                    PaymentResult(success = true, message = "Purchase consumed")
                )
            } else {
                _paymentState.value = PaymentState.Error("Failed to consume purchase")
            }
        }
    }

    fun topUpWallet(amount: BigDecimal, description: String = "Wallet Top Up") {
        if (!rateLimiter.allowRequest()) {
            _paymentState.value = PaymentState.Error("Too many requests. Please try again later.")
            return
        }

        viewModelScope.launch(Dispatchers.IO) {
            _paymentState.postValue(PaymentState.Loading)

            val validation = TransactionValidator.validateAmount(amount)
            if (!validation.isValid) {
                _paymentState.postValue(PaymentState.Error(validation.message))
                return@launch
            }

            val result = walletManager.topUp(amount, description)
            if (result.success) {
                _paymentState.postValue(PaymentState.WalletUpdated(walletManager.getBalance()))
            } else {
                _paymentState.postValue(PaymentState.Error(result.message, result.errorCode))
            }
        }
    }

    fun debitWallet(amount: BigDecimal, description: String = "Purchase") {
        if (!rateLimiter.allowRequest()) {
            _paymentState.value = PaymentState.Error("Too many requests. Please try again later.")
            return
        }

        viewModelScope.launch(Dispatchers.IO) {
            _paymentState.postValue(PaymentState.Loading)

            val validation = TransactionValidator.validateAmount(amount)
            if (!validation.isValid) {
                _paymentState.postValue(PaymentState.Error(validation.message))
                return@launch
            }

            val result = walletManager.debit(amount, description)
            if (result.success) {
                _paymentState.postValue(PaymentState.WalletUpdated(walletManager.getBalance()))
            } else {
                _paymentState.postValue(PaymentState.Error(result.message, result.errorCode))
            }
        }
    }

    fun creditWallet(amount: BigDecimal, description: String = "Credit") {
        if (!rateLimiter.allowRequest()) {
            _paymentState.value = PaymentState.Error("Too many requests. Please try again later.")
            return
        }

        viewModelScope.launch(Dispatchers.IO) {
            _paymentState.postValue(PaymentState.Loading)

            val validation = TransactionValidator.validateAmount(amount)
            if (!validation.isValid) {
                _paymentState.postValue(PaymentState.Error(validation.message))
                return@launch
            }

            val result = walletManager.credit(amount, description)
            if (result.success) {
                _paymentState.postValue(PaymentState.WalletUpdated(walletManager.getBalance()))
            } else {
                _paymentState.postValue(PaymentState.Error(result.message, result.errorCode))
            }
        }
    }

    fun refundTransaction(transactionId: String, amount: BigDecimal) {
        if (!rateLimiter.allowRequest()) {
            _paymentState.value = PaymentState.Error("Too many requests. Please try again later.")
            return
        }

        viewModelScope.launch(Dispatchers.IO) {
            _paymentState.postValue(PaymentState.Loading)

            val validation = TransactionValidator.validateAmount(amount)
            if (!validation.isValid) {
                _paymentState.postValue(PaymentState.Error(validation.message))
                return@launch
            }

            val result = walletManager.refund(transactionId, amount)
            if (result.success) {
                _paymentState.postValue(PaymentState.WalletUpdated(walletManager.getBalance()))
            } else {
                _paymentState.postValue(PaymentState.Error(result.message, result.errorCode))
            }
        }
    }

    fun loadTransactionHistory() {
        viewModelScope.launch(Dispatchers.IO) {
            _paymentState.postValue(PaymentState.Loading)
            val transactions = walletManager.getTransactionHistory()
            _paymentState.postValue(PaymentState.TransactionHistoryLoaded(transactions))
        }
    }

    fun getWalletBalance(): WalletBalance {
        return walletManager.getBalance()
    }

    override fun onCleared() {
        super.onCleared()
        billingManager.destroy()
    }
}

// ==================== Payment Processor Facade ====================

class PaymentProcessor private constructor(private val context: Context) {

    companion object {
        @Volatile
        private var instance: PaymentProcessor? = null

        fun getInstance(context: Context): PaymentProcessor {
            return instance ?: synchronized(this) {
                instance ?: PaymentProcessor(context.applicationContext).also { instance = it }
            }
        }
    }

    private val billingManager = BillingManager(context, CoroutineScope(Dispatchers.Main + SupervisorJob()))
    private val walletManager = WalletManager(context)
    private val securityManager = SecurityManager(context)
    private val rateLimiter = RateLimiter()

    fun initialize() {
        billingManager.initialize()
    }

    fun getBillingManager(): BillingManager = billingManager

    fun getWalletManager(): WalletManager = walletManager

    fun getSecurityManager(): SecurityManager = securityManager

    suspend fun queryInAppProducts(productIds: List<String>): List<ProductInfo> {
        return billingManager.queryProducts(productIds, BillingClient.ProductType.INAPP)
    }

    suspend fun querySubscriptions(productIds: List<String>): List<ProductInfo> {
        return billingManager.queryProducts(productIds, BillingClient.ProductType.SUBS)
    }

    fun purchaseInApp(activity: Activity, productId: String): Boolean {
        if (!rateLimiter.allowRequest()) return false
        return billingManager.launchPurchaseFlow(activity, productId)
    }

    fun purchaseSubscription(activity: Activity, productId: String, offerToken: String): Boolean {
        if (!rateLimiter.allowRequest()) return false
        return billingManager.launchSubscriptionFlow(activity, productId, offerToken)
    }

    fun walletTopUp(amount: BigDecimal, description: String = "Top Up"): PaymentResult {
        if (!rateLimiter.allowRequest()) {
            return PaymentResult(false, message = "Rate limit exceeded")
        }
        val validation = TransactionValidator.validateAmount(amount)
        if (!validation.isValid) {
            return PaymentResult(false, message = validation.message)
        }
        return walletManager.topUp(amount, description)
    }

    fun walletDebit(amount: BigDecimal, description: String = "Purchase"): PaymentResult {
        if (!rateLimiter.allowRequest()) {
            return PaymentResult(false, message = "Rate limit exceeded")
        }
        val validation = TransactionValidator.validateAmount(amount)
        if (!validation.isValid) {
            return PaymentResult(false, message = validation.message)
        }
        return walletManager.debit(amount, description)
    }

    fun walletCredit(amount: BigDecimal, description: String = "Credit"): PaymentResult {
        if (!rateLimiter.allowRequest()) {
            return PaymentResult(false, message = "Rate limit exceeded")
        }
        val validation = TransactionValidator.validateAmount(amount)
        if (!validation.isValid) {
            return PaymentResult(false, message = validation.message)
        }
        return walletManager.credit(amount, description)
    }

    fun getWalletBalance(): WalletBalance = walletManager.getBalance()

    fun getTransactionHistory(): List<WalletTransaction> = walletManager.getTransactionHistory()

    fun destroy() {
        billingManager.destroy()
        instance = null
    }
}